INSERT INTO `buzzes` (`buz_id`, `member_id`, `prof_id`, `buz_cdate`, `buz_show`, `buz_content`) VALUES
(1, 10, 5, 1765343119, 1, '確かな英語力と引き出しの多い会話力、どちらもお持ちのとても親しみやすく明るい先生だと思いました。発音もとても美しく、わかりやすい英語で話して頂けるのでオールイングリッシュのレッスンもお薦め致します。'),
(2, 10, 5, 1765343145, 1, '優しい雰囲気で聞き上手な先生です。人生経験豊富な先生なので、関西弁を交えつつ、自分の人生を英語で表現してもらい、いいリスニングの授業になりました。発音も上手で、ちょうどリスニングを鍛えたかったのでよかったです。'),
(3, 10, 5, 1765343158, 1, '先生が話し易いお人柄なのと、レッスン内容も楽しいので続けて受講しております。題材や進め方についてこちらの希望を組み入れて頂けるのでありがたいです。'),
(4, 10, 5, 1765343170, 1, 'いつも子供が楽しく授業受けさせてもらっています。子供が考えて答えようとするのを、しっかり待っていただいたり、とても優しくリードしていただけるので、安心して任せていられます。'),
(5, 10, 5, 1765343180, 1, '体験で今回のレッスンを受けました。初めてのオンライン英会話でとても緊張しましたが、先生が優しく促してくださったので安心しました。今後も続けたいと思います。'),
(6, 10, 5, 1765343192, 1, '今までどう言えばいいのだろうと悶々としていたことが解決できるような気がしました。キャリー先生は親しみやすい雰囲気で、安心して話すことができる気がしました。'),
(7, 10, 5, 1765343200, 1, '何度もお世話になっております。前回までの復習と新しい単語を教えていただいたようです。いつもとても丁寧に教えていただけるし、優しいだけでなく面白さもあるので、飽きっぽい娘も続けていけています。'),
(8, 10, 5, 1765343208, 1, 'いつも丁寧に教えてくださります。今日はたくさん新しい単語を習ったようです。理解できることが増えてきたようで、キャリー先生のおかげで英語の楽しさがわかってきたようです。'),
(9, 10, 5, 1765343217, 1, '初めてのレッスンで緊張していましたが、とても気さくに話しかけて頂き、とても楽しいレッスンでした。英会話初級レベルですが、学習の進め方もとてもよく、続けていけそうな気になりました。'),
(10, 10, 5, 1765343226, 1, 'もう何度もお世話になっています。娘の大のお気に入りの先生です。丁寧に指導していただき褒めてくださるので、回数を重ねることに自信がついているようです。'),
(11, 10, 5, 1765343234, 1, '今日は新しい単語を教えていただいたようです。しっかり覚えたい！とやる気満々でした。先生の教え方のお陰だと思います。ずっと教えて頂きたい先生です。'),
(12, 10, 5, 1765343243, 1, '終始にこにこと優しい雰囲気で話を聞いてくださり、とてもリラックスしてお話ができました！会話で使えるフレーズ少しずつ丁寧に教えてくださり、生きた英語を習得できそうだなと思いました。'),
(13, 10, 5, 1765343252, 1, 'とにかく英語を話すことが重要と考えていましたが、丁寧に説明してもらうことも必要だと思いました。ネイティブ的な表現の説明が大変参考になります。'),
(14, 10, 5, 1765343264, 1, '今回もネイティブ的な表現を紹介していただき、参考になりました。知らなかった単語だけでなく、知っている単語でもこういう使い方をするのかと思いました。'),
(15, 10, 5, 1765343275, 1, '実践的な英語を教えていただき、すごく勉強になりました!どこを強調して読めばいいのか具体性があり、楽しく学べました。またお願いしたい先生です♪'),
(16, 10, 5, 1765343286, 1, '初めてのレッスンでしたが、レッスン前に緊張していたのを忘れて楽しく受講することができました。私の言うこともじっくりと聞いていただけて、安心感のある授業でした。また受けてみたいと思います。'),
(17, 10, 5, 1765343317, 1, '私がしていただきたいレッスンをこんなに濃く教えていただけてビックリしました！！これを元に次回もレッスンしていただける方法も斬新で素晴らしいです(^o^ゞ'),
(18, 10, 6, 1766456741, 1, '小学１年生の娘の対応をいただきました。担当の先生はとても丁寧で優しく、楽しく受講していました。今回は無料体験でしたが、今後も継続利用したいと思います。'),
(19, 10, 6, 1766456932, 1, '今日も楽しく授業が出来ました。\n日頃のわからない英語を丁寧に教えて頂き助かりました！'),
(20, 10, 6, 1766456942, 1, '本日はキッズ向けのレッスンを体験させていただきました。\n子供も緊張はしていたようですが、楽しくレッスンを受けられたようで安心致しました。終始優しく教えて頂き、感謝しております。'),
(21, 10, 6, 1766456949, 1, '初レッスンで子供は緊張していたようでしたが、先生が優しく話してくださったので楽しかったようです。'),
(22, 10, 6, 1766456957, 1, '日記の添削をすすめてくれました。\n発音が良いのでリスニングの勉強になります。\n文法も教えていただけました。'),
(23, 10, 6, 1766456967, 1, '子供がまだレッスンに慣れていないことを事前に伝えたところ、日本語を混えてわかりやすく、またクイズ形式で楽しくレッスンを受けることができました。また英語で復唱するよう言われても対応できてないことを伝えたら、そこも日本語で伝えてくれたことで、今までで一番英語の発話をできていたのでよかったです。'),
(24, 10, 6, 1766456974, 1, '初回レッスンを受講させていただきました。全然英語が話せない、理解できない状況ですが、私にも理解できるレベルに合わせてレッスンいただきました。今後のレッスンプランも詳細にご提案いただきました。あっという間の25分で、非常に内容の濃いレッスンを受講することできました。\n僭越ながら、英語に関する造詣が深いこともちろん、発音はいうまでもなく、その他のお話もすべてが、大変楽しいうえ、多くの気づきを頂戴できたレッスンでした。ワールドトークで最高の先生のおひとりだと思います。'),
(25, 10, 6, 1766456983, 1, '明るく色々と話しかけていただきました、ありがとうございました。またレッスンをお願いしたいと思います。'),
(26, 10, 6, 1766456988, 1, 'ネイティブのような発音と表現方法を使ってレッスンしていただけるので大変勉強になります。またディスカッションのレッスンもして頂き、実際に役に立つレッスンです。'),
(27, 10, 6, 1766456994, 1, 'まずは初めのご挨拶から英語力をご判断頂き、これからの方向性を確認しました。\nまた、先生の英語を普段から身近な物にする取り組みも教えて頂き良かったです。'),
(28, 10, 6, 1766457000, 1, '初めてのレッスンで緊張していましたが、初心者の私に優しく的確なアドバイスをいただき、満足しています。なんとか続けられそうです。ありがとうございます。'),
(29, 10, 6, 1766457007, 1, '楽しかったようで、終わってすぐに『早く次の予約して！！明日でもいいから！！』と嬉しそうに言っていました。少し『お勉強的なレッスン』に嫌気が来ているようなので、気分転換にもなったようでよかったです。'),
(30, 10, 6, 1766457012, 1, '初めてのLessonでしたが、好きなものを聞いてくださったり、優しく丁寧な授業で、子供も楽しそうにしていました。ありがとうございました。'),
(31, 10, 1, 1766458120, 1, '最初はついていけるか不安でしたが、周りの受講生のやる気にモチベーションも上がりました。個人的には、宿題等の負荷がある方が強制的に勉強できる時間も作れたので、頑張れたポイントです。また、いつも思った以上に細かい英作文の添削や長文読解の資料などを提供してくれます。独学では手に届かないところを丁寧に進めてくれる、そんな講座です。'),
(32, 10, 1, 1766458154, 1, '本講座を2ヶ月受講いたしまして、宿題提出はいつもギリギリでしたが、グループメンバーの方々と毎週勉強する習慣ができ、モチベーションがあがり、このたび講座最終の7月のTOEICにて自己ベストを更新することができました。2ヶ月とても丁寧に指導いただいたおかげです。Akane先生、ありがとうございました。'),
(33, 10, 1, 1766458168, 1, '人生で一番英語の勉強に取り組めた３か月間だったと思います。こんなに頑張れた自分を褒めてあげたい！と思うほどでした。でも、これは間違いなく、あかね先生のおかげです。いつも、あかね先生の笑顔、明るい声でモチベーションがあがりました。また、英語の勉強法の指導も大変適格でした。毎回宿題を的確に分析してくださり、実力がついていることも実感することができました。メンバーにも大変恵まれたこともとても大きかったと思います。「途中で脱落するだろう」と思って始めたのが、信じられないくらい・・。ちなみに、この３か月、モチベーションが上がって、個人のいつものワールドトークレッスンも、むしろハイペースで進められていまし'),
(34, 10, 1, 1766458181, 1, 'これまで複数回受講させていただいています。あかね先生のご指導は大変丁寧でわかりやすく、確実に実力が上がります。それだけでなく、グループレッスンではいつも不思議と参加メンバーにも恵まれていると感じます。双方向の対話が適度にあるレッスンなので、初めは少し緊張しますが、回を重ねる毎に、お互いのことが分かってきて、メンバー同士のレスペクトや連帯感が出てきます。学習方法を共有したりする時間もとっていただけるため、とても参考になります。一人だったらあんなに頑張ることは絶対にできなかった、といつも感じていて、開講してくださったあかね先生や参加メンバーに感謝しています。'),
(35, 10, 1, 1766458344, 1, 'ありがとうございました。一度もビデオオンにせず、失礼しました。先生は受講生の表情が見えずやりにくい面があったかもしれませんが、受ける側からすると、家族が近くにいたりする環境のなかでの受講だったので、オフで参加させていただき、助かりました。\nTOEIC900点超えたいです！今、865点ぐらい。講座開設お願いします！そしていつか英検1級講座もお願いします。'),
(36, 10, 1, 1766458351, 1, '3ヶ月間ありがとうございました。とても丁寧でわかりやすく教えてくださりありがとうございました。'),
(37, 10, 1, 1766458360, 1, '今回レベルが高くて、ついていけるか心配だった。いい刺激になった。同じような講座があれば、検討したい。Akan先生が詳しく教えてくれた。宿題をこなすのがきつかったが、なんとかがんばった。自分一人ではここまでしなかったと思う。'),
(38, 10, 1, 1766458396, 1, '3か月間、ありがとうございました。先生の雰囲気もやわらかく、説明もわかりやすかったです。ただ、一回６０分は短く感じました。６０分講義プラス２０分の質疑応答などだと良かったと思います！また機会があれば参加したいと思います！'),
(39, 10, 1, 1766458402, 1, 'Akane先生の説明がとてもわかりやすく、またやさしいお人柄で、楽しくレッスンが受講できました。今後機会があれば個人レッスンも受けたいと思いました。'),
(40, 10, 1, 1766458415, 1, '講師のAkane先生がとても優秀な方で、独学で挫折しそうな問題にもわかりやすく簡潔に解説いただけた。\n難しい問題集の公式問題集リーディング編を全てやり切ることができた。\n毎週宿題を課せられることによって、どんなに忙しくても問題を解くという学習習慣がついた。'),
(41, 10, 3, 1768891115, 1, '息子の英検準1級のライティングをお願いしたのですが、初めてにもかかわらず丁寧に教えていただき、息子も一生懸命レッスンしてました。また次回もお願いしたいです。'),
(42, 10, 3, 1768891122, 1, '子どものレッスンをお願いしています。英検のレッスンをお願いしても、フリートークをお願いしても、何にでも対応できる完璧な先生だと思いました。これからもお世話になりたいと思っております。どうぞよろしくお願いいたします。'),
(43, 10, 3, 1768891138, 1, 'Kohay先生、念願の英検１級に合格できました。どんなに出来が悪くてもいつも優しくて爽やかな笑顔で迎えてくださってレッスンをしていただきました。心が折れそうな時も諦めなかったのは先生のおかげです。本当にありがとうございました。'),
(44, 10, 3, 1768891150, 1, '先生のおかげで、今回英検1級二次試験無事に合格しました。1年間大変お世話になっております。またよろしくお願いいたします。'),
(45, 10, 3, 1768891169, 1, '小学1年生の息子（英検2級合格済）の英会話力維持の為、レッスンをお願いしました。以前 英検2級対策でもお世話になりKohay先生のレッスンの質の高さは存じ上げておりましたが、やはり素晴らしいです！時事問題、社会問題等を幼児の息子にわかりやすくAll English でディスカッションをしていただけます。準1級受験に向けて、改めて、Kohay先生にご指導いただきたいと思いました。'),
(46, 10, 3, 1768891180, 1, 'Kohay先生による英検準一級の英作文の添削レッスンを今回を含め数回行いました。先生の英語学習の経験から裏付けられた英語表現は英検準一級の英作文の語彙パートで満点の獲得につながりました。'),
(47, 10, 3, 1768891188, 1, 'いつもは英検準1級のリスニングをメインでやっていますが、今日はリーディングの解説をしていただきました。自分で解いた時は、あまりしっくりきていなくて、自信がなかった解答もレッスン後には内容や、解き方含めて全てすっきりしています！25分という短い時間内でもいつも学びの多いレッスンを提供していただき、感謝しています！'),
(48, 10, 3, 1768891198, 1, '時間内に英検や、長文読解に共通する裏技のようなものをぎっしりと教えてくださるので、毎回とてもためになります！'),
(49, 10, 3, 1768891206, 1, '数年間、英検準1級の勉強をしてきて、やっと自分のリスニングの弱点や聞き取りのポイントを明確に指摘してくれる講師に出会うことができました。'),
(50, 10, 3, 1768891212, 1, '英検準１級に向けての勉強方法や、参考書などを教えていただきました。英検のこともとても詳しかったので、これから先生に教えていただきたいと思いました。スライドを用いて説明していただけたので、とても分かりやすかったです。'),
(51, 10, 3, 1768891221, 1, '英検の読解の問題について教わりました。英検の問題なのに、まるで宝探しのようなワクワク感がありました。とても楽しい授業でした。ありがとうございます！！'),
(52, 10, 3, 1768891229, 1, '英検１級二次試験対策をしていただきありがとうございました。今までは聞いたことのない新しい観点でのアドバイスをいただき、目から鱗が落ちるような気持ちでした。早速取り入れてみたいと思いました。また、レッスンが始まった時は緊張していたのですが先生のお人柄で緊張が段々とほぐれて落ち着いてレッスンを受けられました。ありがとうございました。'),
(53, 10, 3, 1768891236, 1, '英検準一級の二次試験対策のレッスンを受けました。時間配分のアドバイスや解答を添削してもらえるので、自分の反省点を改善しやすいです。'),
(54, 10, 3, 1768891244, 1, '英検準一級の二次試験対策レッスンを受けました。スピーキングを沢山練習させてもらいました。単語や前置詞などの正しい表現方法、聞き取りづらい単語も教えていただきました。'),
(55, 10, 3, 1768891254, 1, '英検準一級リスニングのレッスンを受けました。不正解だった問題にも解説を頂きました。目標の点数も具体的に教えてもらったのでやる気がもっと出ました。'),
(56, 10, 3, 1768891260, 1, '準１級の読解を一緒にやってもらいました。まったく難しいのですが、方向性がみえてきました。KOHAY先生はさすがです。'),
(57, 10, 3, 1768891269, 1, '先生に教えてもらったトレーニングで読解が速くなりました。これからも続けていきます。英検準一級の英作文の添削して頂き、書き方も教えて頂いたので、こちらの練習も続けていきたいです。'),
(58, 10, 3, 1768891283, 1, '英検準一級の読解対策をしていただきました。問題を解く時に助けになる考え方を教えてもらい、実際に解きやすくなりました。ありがとうございました。'),
(59, 10, 3, 1768891288, 1, '英検について詳しくアドバイス頂きました。一つの目標として受験を考えてみようかなと思い至りました。適切な助言をありがとうございました。落ち着いた中にも優しさのあふれた先生、どんなレベルの方にも対応できる英語のエキスパートであると同時に、英語学習の伴走者になろうとして下さる熱心な先生だと感じました。'),
(60, 10, 7, 1769403087, 0, 'わかりやすい解説をしてくださる先生でした。\n性格も明るい先生だったので、私まで気分が明るくなりました。'),
(61, 10, 7, 1769403093, 1, 'とても元気な先生で、パワーをもらいました。\n英語の目標を考えている途中でお会いでき、よかったです。\n次も予約しております。'),
(62, 10, 7, 1769403099, 1, '初めてのレッスンで開始3分くらい緊張しておりましたが、先生のお人柄で緊張も解れやる気も沸きました!'),
(63, 10, 7, 1769403105, 1, '様々なレベルの先生がいらっしゃるようにお見受けしますが、こちらの先生の英語はネイティブレベルです。褒め上手で、明るく、説明もとても上手です。'),
(64, 10, 7, 1769403116, 1, 'Yoshino K先生のおかげで、英検合格することができました！いつも明るく楽しいレッスンをありがとうございます。これからもよろしくお願いいたします。'),
(65, 10, 7, 1769403127, 1, 'とても有意義なレッスンで、丁寧なフィードバックも下さって勉強になります。定期的にレッスンをお願いしたいと思います。'),
(66, 10, 7, 1769403135, 1, '英語勉強のアドバイスありがとうございました✨\n図でのイメージ見える化で、すごくわかりやすかったです。\nいつも風のようにさわやかで、春や冬、秋の太陽のようにあたたかいレッスン✨英語勉強の励みになります( ^)o(^ )'),
(67, 10, 7, 1769403144, 1, '今回もスーパー分かりやすく、サポート力ばつぐんのレッスンをありがとうございました✨英語きょーふがうすらいで、英語を勉強するのはたのしいのかもしれない、に変わっていきそうです✨'),
(68, 10, 7, 1769403165, 1, '今回も超初心者でも楽しめてかつ！絶対にやくだちそうな単語を手とりあしとりレッスン、ありがとうございました。こんども楽しみです( ^)o(^ )'),
(69, 10, 7, 1769403170, 1, 'とっても明るく緊張せずレッスンを受けることが出来ました。とても良い先生だと思います！'),
(70, 10, 7, 1769403178, 1, '英語超×３初心者のため、劣等感ばかりのわたしでしたが、超×３のレベルでも無理なく、分かりやすいレッスンをとても楽しく受けれることができました。'),
(71, 10, 7, 1769403197, 1, 'Yoshino先生のレッスンは最高です！レッスンは毎回深い学びがあり、私もいつか先生のように話せるようになりたいと思いました。その為にもっともっと努力をしていきたいと思います。夏休みに入ったらレッスン時間を増やせるので頑張ります。これからもどうぞよろしくお願いいたします。'),
(72, 10, 7, 1769403203, 1, 'Yoshino先生はいつも明るく楽しいレッスンで、毎回楽しみにしております。夏休みにたくさん予約を入れて、集中して頑張りたいと思います。'),
(73, 10, 7, 1769403209, 1, 'わからなかったところをわかるまで細かく教えてくださりました。'),
(74, 10, 7, 1769403227, 1, '今回も質問に対して一緒に解決してくれたので、わからないことを気軽に聞くことができました。'),
(75, 10, 7, 1769403238, 1, '今回も英語でたくさんお話しできて、とても充実したレッスンになりました。ありがとうございます。\n新しい仕事が決まったこともご報告できて良かったですし、喜んでいただいたのもとてもうれしかったです。\nまた楽しいレッスンをお願いしますね！'),
(76, 10, 7, 1769403244, 1, 'とても楽しくて陽気な先生と朝からお話しできて、たくさん元気をいただきました。英語ではどのように言うのか、気になっていた言葉についてもいろいろ教えていただいたので、とても勉強になりました。また次回もお願いしますね！'),
(77, 10, 7, 1769403251, 1, '今回も、明るくて笑顔がとても素敵な先生のおかげで、楽しいレッスンになりました。\n私は日本語に逃げそうになるのですが、終始英語で対応していただいたので、何とか留まることができました。\nありがとうございます。またお願いしますね！'),
(78, 10, 7, 1769403256, 1, '本日は初回のレッスンありがとうございました！\n私が主に学びたい英語の発音について今後のレッスンプランなどを教えていただけたので、どのように勉強を進めていくかのイメージがつきやすくてありがたかったです！\nこれからもよろしくお願いします！'),
(79, 10, 7, 1769403269, 1, 'とても明るくて、褒め上手で、聞き上手で、そして話し上手な素晴らしい先生だと思いました。\nいろいろなトピックについて、またお話ししたいです。\n今回もありましたが、どうしても言葉が上手く出てこないときがあるので、次回からは相談しながら受講したいです。\nありがとうございました！'),
(80, 10, 7, 1769403280, 1, '初めてのレッスンで緊張してましたが、明るく楽しく教えて頂き\nこれからも続けていきたいと思います！！');
