INSERT INTO `courses` (`course_id`, `prof_id`, `course_cdate`, `course_mdate`, `course_status`, `course_name`, `course_copy`, `course_fee`, `course_price`, `course_start_date`, `course_end_date`, `course_weekday_mask`, `course_time_start`, `course_time_end`, `course_score`, `course_order_weight`, `course_reco`, `course_step`, `course_ccate_id_1`, `course_ccate_id_2`, `course_logo`, `course_youtube_id`, `course_youtube_id_2`, `course_intro`, `course_memo`, `course_group_flag`, `course_group_upper`, `course_group_limit`, `course_mail_s`, `course_mail_e`, `course_meeting_url`, `course_meeting_id`, `course_meeting_pass`, `course_meeting_type`, `course_syllabus`, `course_material`, `course_total_lessons`, `course_apply_deadline`, `course_landingpage`, `course_apply_form_url`, `course_material_drive_url`) VALUES
(1, 1, 1748257005, 1765335792, 4, 'TOEIC730グループ講座', NULL, 1, 0, NULL, NULL, 64, '00:00:00', '00:01:00', 0, 0, 0, 1, 1, 2, 1, NULL, NULL, '<p>みんなと一緒だから頑張れる！ オンライングループレッスンでTOEIC&reg;スコア730点を目指すコースです これまでワールドトークでは、マンツーマンでのTOEIC&reg;対策レッスンを実施してきましたが、新たに集団型のオンラインTOEIC&reg;講座をはじめます！ 「一人で勉強するのはつらい&hellip;」「モチベーションが続かない&hellip;」 そんなお悩みを持つ方におススメなのは、一緒の目標を持つ学習仲間です。 TOEIC&reg;のスコアアップを目指してみんなで刺激を共有しながら学習できるのがこのコースの特徴です！ 効率よく目標達成をするためにも、最適な学習環境を作りましょう！</p>', '▼宿題のURLはこちらです。\nhttps://www.group.worldtalk.jp/rd/toeic2025.php\n\n※今週、日曜日24時までに送信ください\n※フォームは来週のレッスンまで入力可能です\n', 1, 10, 0, NULL, NULL, NULL, NULL, NULL, 1, 'https://www.group.worldtalk.jp/wte/akanetoeic2025', NULL, 1, NULL, 'https://www.worldtalk.jp/p/toeiccourse2025', NULL, NULL),
(3, 3, 1753428871, 1761618219, 4, '英単語暗記革命!!グループ講座', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 5, 6, 1, NULL, NULL, '「何回書いても覚えられない…」「すぐ忘れてしまう…」\nその悩み、この夏こそ終わらせましょう！\n\n科学的な記憶の仕組みを活用した新感覚の暗記法で、苦手意識を“楽しい学習習慣”に変えていきます。\nこの講座では、“ただの暗記”から三歩進んだ、語彙力の育て方を学びます。\n\n英語教育の理論と実践に精通する大人気講師 Kohay先生が、\nその方法を特別講義で、わかりやすく伝授します。\n\n資格試験の対策にも、語彙力に不安のある方にも。\nこの夏、学び方から英語を変えてみませんか？', NULL, 1, 30, 0, '本レッスンは講義形式のグループ講座です。\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にZoomURLをクリックします\n2.時間になったらルームに入室ができます\n3.レッスンがスタートします\n\n\n■お願いしたいこと\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師が意見を求めたときのみ、マイクをオンにして頂く場合があります。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　各講座が開始する1日前までに事務局へお問い合わせください。\n　\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　customer@worldtalk.jp\n\n\n■アーカイブ動画・感想フォームについて\n-----------------------------\n・各講座終了後、24時間後以内にアップロードいたします。\n・受講者限定で全5回分、2025/9/3(水) 18:00まで公開いたします。\n\n・レッスン毎に、フォームへ感想を書いていただく(脳内整理)予定があります。\n　先生に直接届きますので、ぜひお送りください！\n\n▼アーカイブ動画・感想フォーム\nhttps://drive.google.com/drive/folders/1HAQMm_2Fj-yPY5GRRvV17QZqoPPUxmi4\n', '本レッスンは講義形式のグループ講座です。\n\n■お願いしたいこと\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　各講座が開始する1日前までに事務局へお問い合わせください。\n　\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　customer@worldtalk.jp\n\n■アーカイブ動画・感想フォームについて\n-----------------------------\n・各講座終了後、24時間後以内にアップロードいたします。\n・受講者限定で全5回分、2025/9/3(水) 18:00まで公開いたします。\n\n・レッスン毎に、フォームへ感想を書いていただく(脳内整理)予定があります。\n　先生に直接届きますので、ぜひお送りください！\n\n▼アーカイブ動画・感想フォーム\nhttps://drive.google.com/drive/folders/1HAQMm_2Fj-yPY5GRRvV17QZqoPPUxmi4\n', 'https://us06web.zoom.us/j/83703065625?pwd=mzqjayzP7QTKd5qbgzSnaeRpIK44bR.1', 83703065625, 899435, 1, 'https://www.group.worldtalk.jp/wte/kohayeitango202507', NULL, 0, NULL, 'https://www.worldtalk.jp/p/kohayeitango202507', NULL, NULL),
(4, 4, 1754033997, 1761619497, 4, '英検1級2次完全攻略！グループ講座', 'https://www.group.worldtalk.jp/wte/kazueiken202507', 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 7, 8, 1, NULL, NULL, '「いつか合格したい、英検1級」\nその思いを、今年こそ“現実”に変えませんか？\n\n「独学では限界を感じている…」「一人では続かない…」\nそんな方にこそおすすめなのが、プロ講師と、同じ目標を持つ仲間との学びの場です。\n\nさらにこの講座は、2次対策に取り組みながら、1次ライティング対策にもつながる実践的な内容。\n地に足のついた意見を英語で書きたい、伝えられるようになりたい。\nそんな1次対策中の方にも、必ず役立つプログラムとなっています。', NULL, 1, 5, 0, '本レッスンはグループ形式の講座です。\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にレッスンURLをクリックします\n2.時間になったらルームに入室ができます\n3.レッスンがスタートします\n\n\n■お願いしたいこと\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・レッスンは録音されます。\n　カメラON推奨ですが、OFFでも構いません。\n　\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　customer@worldtalk.jp\n\n', '■宿題について\n-----------------------------\n・本講座では宿題がございます。\n・上記シラバス内の該当日付にある 「宿題フォームはこちら」 をクリックのうえ、ご提出ください。\n・レッスン前日が提出締切です。\n\n■アーカイブ動画について\n-----------------------------\n・各講座終了後、24時間後以内にアップロードいたします。\n・受講生限定で全10回分、2025/10/16(木)18:00まで公開いたします。\n\n▼アーカイブ動画まとめ\nhttps://drive.google.com/drive/folders/1nVFBaoCWLVEKj_G-EDA3lFVNk9Q5au3q', 'https://us06web.zoom.us/j/89518207093?pwd=UuKS6HgmRc8IA9xANofv8PPnjhSHlr.1', 89518207093, 305909, 1, 'https://www.group.worldtalk.jp/wte/kazueiken202507', NULL, 0, NULL, 'https://www.worldtalk.jp/p/kazueiken202507', NULL, NULL),
(5, 4, 1754034071, 1761620631, 4, '大学受験　夏期グループ講座', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 7, 9, 1, NULL, NULL, '大学受験を控える高校1～3年生の方、そして保護者のみなさま。\nこの夏、同じ目標を持つ仲間と一緒に、英語の基礎をゼロから固めるチャンスです。\n\n「時間が足りない」「何から始めればいいか分からない」\nそんな悩み、この講座で解決します！\n\nワールドトーク史上初、「大学受験夏期講座 ―英語基礎固め編―」では、語彙・文法・読解・英作文・リスニングをバランスよく徹底強化。\n\n講師は京都大学卒、上智大学、慶應義塾大学など難関大学合格者を多数輩出する、ワールドトーク随一の実力派 Kazu先生！\n知識を「使える力」へと変えるこの夏、受験英語の土台を確実に築き上げましょう。', NULL, 1, 5, 0, '本レッスンはグループ形式の講座です。\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にレッスンURLをクリックします\n2.時間になったらルームに入室ができます\n3.レッスンがスタートします\n\n\n■お願いしたいこと\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・レッスンは録音されます。\n　カメラON推奨ですが、OFFでも構いません。\n　\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　customer@worldtalk.jp\n', '■宿題について\n-----------------------------\n・本講座では宿題がございます。\n・上記シラバス内の該当日付にある 「宿題フォームはこちら」 をクリックのうえ、ご提出ください。\n・レッスン前日が提出締切です。\n\n■アーカイブ動画について\n-----------------------------\n・各講座終了後、24時間後以内にアップロードいたします。\n・受講生限定で全10回分、2025/10/14(火) 18:00まで公開いたします。\n\n▼アーカイブ動画まとめ\nhttps://drive.google.com/drive/folders/1PYT4MVLr1vkYh4zx1gCyDIKEidHa6NFn\n', 'https://us06web.zoom.us/j/83909969252?pwd=H6eTB6bTHFRg3LgQovVkManBfO1hXe.1', 83909969252, 795800, 1, 'https://www.group.worldtalk.jp/wte/kazudaigakusummer202508', NULL, 0, NULL, 'https://www.worldtalk.jp/p/kazudaigakusummer202508', NULL, NULL),
(6, 1, 1754034693, 1761620589, 4, '英検準1級対策グループ講座', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 1, 10, 1, NULL, NULL, 'この夏、10月の英検準1級合格へ。\n仲間と一緒に、3ヶ月で一気にラストスパート！\n\n「ひとりだと、ついサボってしまう…」\n「なかなか勉強が続かない…」\n\nそんなあなたのための、短期集中・グループ型の英検準1級対策コースです。\n\n全国から集まる受講生と学び合い、毎週の課題提出で“やらざるを得ない環境”を確保します。\n自然と学習リズムが整い、前向きに頑張れます。\n\nこの夏休みを、なんとなくの勉強で終わらせず、\n合格への最短ルートに。\n\n3ヶ月後、自信を持って試験に挑むあなたを、一緒に育てましょう！', NULL, 1, 10, 0, '本レッスンはグループ形式の講座です。\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にZoomURLをクリックします\n2.時間になったらルームに入室ができます\n3.レッスンがスタートします\n\n\n■お願いしたいこと\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・ご不明点がありましたら、運営事務局までご連絡ください。\n　customer@worldtalk.jp', '■共有した資料について\n-----------------------------\nレッスン中に共有した資料の一部は、以下からダウンロードいただけます。\n\n▼資料まとめ\nhttps://drive.google.com/drive/folders/1_oWIQOIXasmizwGCx8RCWJeLwA-KkVrW\n\n■宿題について\n-----------------------------\n・本講座ではDAY0〜DAY9まで、宿題をご用意しています。\n・上記シラバス内の該当日付にある 「宿題フォームはこちら」 をクリックのうえ、ご提出ください。\n・宿題の提出〆切は、原則として【各講座の3日前まで】です。\n', 'https://us06web.zoom.us/j/85265643968?pwd=6Lkqxo44Vt1wdQnneafgoCN2bacttu.1', 85265643968, 846722, 1, 'https://www.group.worldtalk.jp/wte/akaneeikenp1202508', NULL, 0, NULL, 'https://www.worldtalk.jp/p/eikenp1202508', NULL, NULL),
(7, 3, 1757060042, 1761620521, 4, '英検２級直前パック Reading & Listening', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 5, 0, 1, NULL, NULL, '「Readingで確実に点を取りたい」「Listeningに不安がある…」\nそんな方のために用意された、英検2級直前対策・全4回集中講座です。\n\nグループ形式で、試験本番に直結する“解法のコツ”を凝縮。\n予約困難な大人気講師 Kohay先生が、限られた時間で効率的に得点を伸ばす方法をわかりやすく伝授します。\n\n小中高生から大学生、社会人まで幅広く参加可能！\n焦りが募る直前期だからこそ、短期間で変化を実感できるチャンスを一緒に掴みましょう。', NULL, 1, 30, 0, '本レッスンは講義形式のグループ講座です。\n\n■ 2講座（R＆L・Writing）を続けて受講される方へ\n----------------------------------------\n・各講座ごとにレッスンURLが異なります。\n・R＆L講座終了後は退室し、Writing講座のURLから入室してください。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・感想フォーム\n-----------------------------\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2025/10/3(金) 18:00まで ご覧いただけます。(受講者限定)\n・各回終了後は「感想フォーム」へのご記入をぜひお願いします。\n　※先生に直接届きますので、皆様のお声が講座に反映されることがあります！\n\n▼アーカイブ動画・感想フォームまとめ\nhttps://drive.google.com/drive/folders/1yij7TJP8sMqmt7mW1ZzrTq-_HUkxF0Km', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたってのお願い\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットにてお知らせください。\n　事前に伝える場合は、開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・感想フォーム\n-----------------------------\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2025/10/3(金) 18:00まで ご覧いただけます。(受講者限定)\n・各回終了後は「感想フォーム」へのご記入をぜひお願いします。\n　※先生に直接届きますので、皆様のお声が講座に反映されることがあります！\n\n▼アーカイブ動画・感想フォームまとめ\nhttps://drive.google.com/drive/folders/1yij7TJP8sMqmt7mW1ZzrTq-_HUkxF0Km', 'https://us06web.zoom.us/j/85808383275?pwd=7L1AClUldds8uaShP94sMRItdnc1Rk.1', 85808383275, 634226, 1, 'https://www.group.worldtalk.jp/wte/kohayeikenpackagerandl#syllabus', NULL, 0, NULL, 'https://www.worldtalk.jp/p/kohayeikenpackage_randl', NULL, NULL),
(8, 3, 1757060527, 1761620530, 4, '英検２級直前パック Writing ', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 30, 5, 0, 1, NULL, NULL, '「要約問題の解き方がわからない」「英作文の書き方に自信がない…」\nそんな方のための、英検2級直前対策・全4回集中講座です。\n\nグループ形式で試験本番に直結する要約力と英作文力 をぎゅっと凝縮！\n予約困難な大人気講師 Kohay先生が、限られた時間で効率的に得点を伸ばす方法をわかりやすく伝授します。\n\n小中高生から大学生、社会人まで幅広く参加可能！\n焦りが募る直前期だからこそ、短期間でWriting力の変化を実感できるチャンスを一緒に掴みましょう。', NULL, 1, 20, 0, '本レッスンは講義形式のグループ講座です。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・感想フォーム\n-----------------------------\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2025/10/3(金) 18:00まで ご覧いただけます。(受講者限定)\n・各回終了後は「感想フォーム」へのご記入をぜひお願いします。\n　※先生に直接届きますので、皆様のお声が講座に反映されることがあります！\n\n▼アーカイブ動画・感想フォームまとめ\nhttps://drive.google.com/drive/folders/1pOPsPNe6UcN7hEA5bgG9ryuVLYtY4omc', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたって\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・感想フォーム\n-----------------------------\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2025/10/3(金) 18:00まで ご覧いただけます。(受講者限定)\n・各回終了後は「感想フォーム」へのご記入をぜひお願いします。\n　※先生に直接届きますので、皆様のお声が講座に反映されることがあります！\n\n▼アーカイブ動画・感想フォームまとめ\nhttps://drive.google.com/drive/folders/1pOPsPNe6UcN7hEA5bgG9ryuVLYtY4omc', 'https://us06web.zoom.us/j/81804998905?pwd=FrFTQbwxUFybvTUZMlscjmRQiN1Grz.1', 81804998905, 685596, 1, 'https://www.group.worldtalk.jp/wte/kohayeikenpackagew#syllabus', NULL, 0, NULL, 'https://www.worldtalk.jp/p/kohayeikenpackage_w', NULL, NULL),
(9, 1, 1761618716, 1769594402, 4, 'TOEIC® 初心者(500-600点)コース', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 60, 1, 2, 1, NULL, NULL, '3ヶ月間の短期集中型で、TOEIC®500〜600点を目指す初中級者向けの講座です。\n基礎文法や問題の解き方を丁寧に学び直し、毎週の宿題で学習習慣を定着させます。\n仲間と一緒に取り組むことでモチベーションを保ちながら、効率的にスコアアップを目指せます。', NULL, 1, 10, 0, '本講座はグループ形式です。\n当日は、下記の手順に沿ってご参加ください。\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にZoomのURLをクリックします\n2.開始時間になったら、ルームに入室ができます\n3.レッスンがスタートします\n\n■ご協力のお願い\n-----------------------------\n・可能な範囲で、カメラをONにしてご参加ください\n・ZoomのURLを開いたままお待ちください。\n・ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts', '■共有した資料について\n-----------------------------\nレッスン中に使用した資料の一部を、下記よりダウンロードいただけます。\n\n▼資料まとめ\nhttps://drive.google.com/drive/folders/1Q1hzQ26HXR3ZIeNpSv8IOmRWUwLHkkuO\n\n■宿題について\n-----------------------------\n・本講座では DAY0～DAY11 まで、各回ごとに宿題をご用意しています。\n・上記シラバス内の該当日の「宿題範囲」をご確認ください。\n\n※DAY8〜DAY11の宿題は Googleフォームでの提出となります。\n　締切がありますので、期限内にご提出ください。', 'https://us06web.zoom.us/j/87559728508?pwd=yy4XzTepJT5RTRylROGKbm5sKhy2m8.1', 87559728508, 775972, 1, 'https://www.group.worldtalk.jp/wte/akanetoeic600202511', NULL, 0, NULL, 'https://www.worldtalk.jp/p/akanetoeic600202511', NULL, NULL),
(10, 4, 1761619571, 1769594402, 3, '大学入学共通テスト　年内仕上げ講座', NULL, 1, 0, '0000-00-00', '0000-00-00', 0, '00:00:00', '00:00:00', 0, 0, 0, 30, 7, 9, 1, NULL, NULL, '高校1～3年生（高卒生含む）対象の共通テスト対策講座。\n直近3年分の公式過去問を徹底分析し、大問別の攻略法を伝授します。\n時間配分、資料問題の突破、リスニング先読みなど本番直結のテクニックを網羅。\n仲間と切磋琢磨しながら年内に仕上げを完了し、本番に向けて自信を築きます', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, 0, NULL, 'https://www.worldtalk.jp/p/daigakucommontest202511', NULL, NULL),
(11, 3, 1761619779, 1767841730, 4, '英検２級絶対基礎力！', '2ヶ月で合格基礎を完成！Kohayが導く全8回集中講義', 1, 0, '2025-11-11', '2026-01-06', 4, '20:00:00', '20:50:00', 0, 0, 0, 50, 5, 6, 1, NULL, NULL, '<p>本講座では、英検２級合格に必要な「読む・聞く・書く」の力を、２ヶ月で徹底的に鍛えます。 読解では、本文と選択肢の&ldquo;言い換え&rdquo;に対応する力を育て、 英作文は授業内添削で、論理と表現の精度を磨き上げます。 50分&times;8回のレッスンに、合格へ導くためのコツとノウハウを凝縮。 アーカイブ付きだから、期間中いつでも何度でも見返せて、 自分のペースで実力を着実に積み上げられます。 英検1級3回連続合格（奨励賞受賞）、合格者180名超。 予約困難な人気講師Kohay先生が、あなたを合格へ導きます。</p>', NULL, 1, 10, 0, '本レッスンは講義形式のグループ講座です。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\nすべての動画・宿題などは以下のフォルダにまとめています。\n\n▼アーカイブ・宿題まとめ\nhttps://drive.google.com/drive/folders/1y1GhjMqrdToCNGlmyztjA1SX9KXZNWRH\n\n・各回終了後、24時間以内にアーカイブを公開予定です。\n・全8回分を2026年1月13日（火）18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）\n', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたって\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\nすべての動画・宿題などは以下のフォルダにまとめています。\n\n▼アーカイブ・宿題まとめ\nhttps://drive.google.com/drive/folders/1y1GhjMqrdToCNGlmyztjA1SX9KXZNWRH\n\n・各回終了後、24時間以内にアーカイブを公開予定です。\n・全8回分を2026年1月13日（火）18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）\n\n■講師へのご質問について\n-----------------------------\n「レッスン中で質問するのは緊張する…」という方のために、質問フォームをご用意しています。\nお気軽にご利用ください。\n\n▼質問フォーム\nhttps://forms.gle/YAFwr84ZovSxgb5G9\n\n※レッスン時間内に可能な範囲でお答えいたします。\n　すべての質問に対応できない場合もございますのでご了承ください。', 'https://us06web.zoom.us/j/85649312308?pwd=RgjAzr64GeGKwdKvfOwgoVmUECfppv.1', 85649312308, 344165, 1, 'https://group.worldtalk.jp/wte/kohayzettaikisog2202511', NULL, 8, NULL, 'https://www.worldtalk.jp/p/kohayzettaikisog2202511', NULL, NULL),
(12, 3, 1761620053, 1768441459, 4, '英検準２級絶対基礎力！', '英検準２級をゼロから勉強したいけれど、何から始めればいいかわからない――そんな方へ。', 1, 19800, '2025-11-07', '2026-01-09', 32, '20:00:00', '20:50:00', 0, 0, 0, 50, 5, 0, 1, NULL, NULL, '<h4>英検準２級絶対基礎力！✨</h4>\n<p>Kohayが提供する「英検準２級絶対基礎力！」では、英検準２級を受験する皆さまのサポートをします。<span style=\"background-color: #f8e465;\"><strong>今の力を、合格へつながる力に変える２ヶ月へ。</strong></span>一緒に力をつけましょう！</p>\n<p>英検準２級を受験する際、多くの方が「書く力」や「長文を読解する力」に悩まされています。特に、長文が急に難しくなる時期や、初めてのメール作文に不安を感じることもあるでしょう。<br>この講座では、そんな悩みを解消し、合格に必要なスキルをしっかりと身につけることができます。</p>\n<h4>この講座が選ばれる理由</h4>\n<ul>\n<li><strong>３技能を総合強化📚</strong>：読解・リスニング・作文の全てを徹底的に学びます。</li>\n<li><strong>ライブ添削で「書ける自分」に🔥</strong>：その場でアドバイスを受けられるので安心です。</li>\n<li><strong>参加型講義で楽しく定着！🎉</strong>：一緒に学ぶ仲間と共に成長できます。</li>\n</ul>\n<h4>受講後の変化</h4>\n<ul>\n<li>Before: 長文が苦手 &rArr; After: 速く正確に長文が読めるように！</li>\n<li>Before: 英作文が書き出せない &rArr; After: &ldquo;型&rdquo;を使って自信を持って書ける！</li>\n</ul>\n<p>この講座を通じて、英検準２級に必要な知識や技術をしっかり身につけます。<br>どうやって勉強を進めればいいのかが明確になり、合格に向けて自信を持って進むことができるでしょう！🌟</p>', NULL, 1, 10, 0, '本レッスンは講義形式のグループ講座です。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\nすべての動画・宿題などは以下のフォルダにまとめています。\n\n▼アーカイブ・宿題まとめ\nhttps://drive.google.com/drive/folders/1wygV_IE178xIA3BiSwXnYKmhJSTgBAjS\n\n・各回終了後、24時間以内にアーカイブを公開予定です。\n・全8回分を2026年1月16日(金)18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたって\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\nすべての動画・宿題などは以下のフォルダにまとめています。\n\n▼アーカイブ・宿題まとめ\nhttps://drive.google.com/drive/folders/1wygV_IE178xIA3BiSwXnYKmhJSTgBAjS\n\n・各回終了後、24時間以内にアーカイブを公開予定です。\n・全8回分を2026年1月16日(金)18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）\n\n■講師へのご質問について\n-----------------------------\n「レッスン中で質問するのは緊張する…」という方のために、質問フォームをご用意しています。\nお気軽にご利用ください。\n\n▼質問フォーム\nhttps://forms.gle/wag81u2QHUBT12eWA\n\n※レッスン時間内に可能な範囲でお答えいたします。\n　すべての質問に対応できない場合もございますのでご了承ください。', 'https://us06web.zoom.us/j/85132515644?pwd=Tr1ne7EBf5W5qy8MWaRJajtwtuIqfL.1', 85132515644, 894215, 1, 'https://group.worldtalk.jp/wte/kohayzettaikisogpre2202511', NULL, 8, NULL, 'https://www.worldtalk.jp/p/kohayzettaikisogpre2202511', NULL, NULL),
(27, 3, 1765331544, 1769414487, 4, '英検準１級直前パック Reading & Listening', '直前期に必要な力を全4回・200分でまとめて対策！英検直前パックでは、「Reading・Listening」「Writing」の得点につながる部分だけを短期集中で整理し、解法・書き方を効率良く習得できます。  英検1級3回連続合格（奨励賞）・TOEIC満点5回、合格者190名超。 圧倒的実績を持つKohay先生が担当します！  小中高生から大学生、社会人まで幅広く参加可能。 迷いをなくして本番に臨める力を着実に育てます。', 1, 9800, '2026-01-11', '2026-01-22', 17, '21:00:00', '21:50:00', 0, 0, 0, 50, 5, 0, 1, NULL, NULL, '<p><strong>直前期に必要な力を全4回・200分でまとめて対策！</strong></p>\n<p>英検直前パックでは、「Reading・Listeningの得点につながる部分だけを短期集中で整理し、解法・書き方を効率良く習得できます。</p>\n<p>英検1級3回連続合格（奨励賞）・TOEIC満点5回、合格者190名超。<br>圧倒的実績を持つKohay先生が担当します！</p>\n<p>小中高生から大学生、社会人まで幅広く参加可能。<br>迷いをなくして本番に臨める力を着実に育てます。</p>', NULL, 1, 30, 0, '本レッスンは講義形式のグループ講座です。\n\n■ 2講座（R＆L・Writing）を続けて受講される方へ\n----------------------------------------\n・各講座ごとにレッスンURLが異なります。\n・R＆L講座終了後は退室し、Writing講座のURLから入室してください。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\n・すべての動画・宿題などは上記「教材GoogleDrive(アーカイブ・宿題など）」のURLへアクセスしてください。\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2026/1/30(金) 18:00まで視聴できます。', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたってのお願い\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットにてお知らせください。\n　事前に伝える場合は、開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\n・すべての動画・宿題などは上記「教材GoogleDrive(アーカイブ・宿題など）」のURLへアクセスしてください。\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2026/1/30(金) 18:00まで視聴できます。', 'https://us06web.zoom.us/j/88660771737?pwd=GLwpvb1wGYevCa3Quchlu9o5dtEFMU.1', 88660771737, 46325, 1, 'https://www.group.worldtalk.jp/wte/kohayeikenpackagepre1randl202601', NULL, 4, NULL, 'https://www.worldtalk.jp/p/kohayeikenpackagepre1_202601', NULL, 'https://drive.google.com/drive/folders/181Apia3S1JQgkyI4S2loo-IXiv-7Os-e'),
(28, 3, 1765331870, 1769414499, 4, '英検準１級直前パック Writing', '直前期に必要な力を全4回・200分でまとめて対策！英検直前パックでは、「Reading・Listening」「Writing」の得点につながる部分だけを短期集中で整理し、解法・書き方を効率良く習得できます。  英検1級3回連続合格（奨励賞）・TOEIC満点5回、合格者190名超。 圧倒的実績を持つKohay先生が担当します！  小中高生から大学生、社会人まで幅広く参加可能。 迷いをなくして本番に臨める力を着実に育てます。', 1, 9800, '2026-01-11', '2026-01-22', 17, '22:00:00', '22:50:00', 0, 0, 0, 50, 5, 0, 1, NULL, NULL, '<p><strong>直前期に必要な力を全4回・200分でまとめて対策！</strong></p>\n<p>英検直前パックでは、「Writing」の得点につながる部分だけを短期集中で整理し、解法・書き方を効率良く習得できます。</p>\n<p>英検1級3回連続合格（奨励賞）・TOEIC満点5回、合格者190名超。<br>圧倒的実績を持つKohay先生が担当します！</p>\n<p>小中高生から大学生、社会人まで幅広く参加可能。<br>迷いをなくして本番に臨める力を着実に育てます。</p>', NULL, 1, 30, 0, '本レッスンは講義形式のグループ講座です。\n\n■レッスンの流れ\n-----------------------------\n1.開始前にZoomのURLをクリック\n2.時間になったらルームに入室できます\n3.レッスンがスタートします\n\n■ご受講にあたって\n-----------------------------\n・ZoomのURLを開いたままお待ちください。\n・講座中はビデオとマイクを基本的にオフにしてください。\n・講師から意見を求められた場合のみ、マイクをオンにしてください。\n・個別指名を希望しない方は、講座中に講師へ個別チャットでお知らせいただくか、\n　開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\n・すべての動画・宿題などは上記「教材GoogleDrive(アーカイブ・宿題など）」のURLへアクセスしてください。\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2026/1/30(金) 18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）', '本レッスンは講義形式のグループ講座です。\n\n■ご受講にあたってのお願い\n-----------------------------\n・個別指名を希望しない方は、講座中に講師へ個別チャットにてお知らせください。\n　事前に伝える場合は、開始1日前までに事務局へご連絡ください。\n\n　ご不明点がありましたら、運営事務局までご連絡ください。\n　https://www.worldtalk.jp/contacts\n\n■アーカイブ動画・宿題等について\n-----------------------------\n・すべての動画・宿題などは上記「教材GoogleDrive(アーカイブ・宿題など）」のURLへアクセスしてください。\n・各回終了後、24時間以内に動画を公開いたします。\n・全4回分を 2026/1/30(金) 18:00まで視聴できます。\n・宿題範囲は「シラバス」をご参照ください。\n・Writing課題はライブ添削を行います\n （提出人数により抽選となる場合があります）', 'https://us06web.zoom.us/j/87028978175?pwd=4za4l26f7YJ9aUJ0bPAT6xglsGP45B.1', 87028978175, 497914, 1, 'https://www.group.worldtalk.jp/wte/kohayeikenpackagepre1w202601', NULL, 4, NULL, 'https://www.worldtalk.jp/p/kohayeikenpackagepre1_202601', NULL, 'https://drive.google.co