INSERT INTO `tmpls` (`tmpl_id`, `tmpl_content`) VALUES
('adm9001', 'Subject: [%product_name%] 日別利用状況レポート - %dt_Y%年%dt_m%月%dt_d%日（%dt_wj%）\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %pub_from%\n\n日別利用状況レポート - %dt_Y%年%dt_m%月%dt_d%日（%dt_wj%）\n\n■会員数\n・本日の新規登録数：%new_member_num% 人\n・会員合計数：%member_num% 人\n\n※ 本日の新規登録数は、当日に仮登録から本登録までを完了したものが対象です。\n※ 会員合計数は、仮登録状態の会員は含まれません。\n\n■本日の購入ポイント数\n・銀行振込の単発購入：%point_43% pt\n・クレジット単発購入：%point_41% pt\n・クレジット自動課金：%point_42% pt\n────────────────────\n・合計：%point_sum% pt\n\n※ 銀行振り込みの場合、管理メニューからポイントをチャージした日付が基準となります。\n 　銀行振り込み申請日が基準ではありません。\n\n■月額コースの合計会員数\n%subscriber_num% 人\n\n※ 現実点で課金継続中の会員が対象です。'),
('buz9001', 'Subject: [%product_name%] クチコミ投稿通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り、%prof_handle%さんのクチコミ投稿を受け付けました。\nご投稿、ありがとうございます。\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■送信内容\n──────────────────────────────────\n・%prof_caption%： %prof_handle% さん\n・メッセージ\n\n%buz_content%\n\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%prof_caption%宛のクチコミは、%prof_caption%詳細ページで\n取り上げられることがございます。\n\nまた今後もレッスンを受講された場合は、ぜひご投稿ください。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('buz9002', 'Subject: [%product_name%] クチコミ投稿通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%prof_lastname% %prof_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り、%member_handle%さんからクチコミ投稿を受け付けました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■受信内容\n──────────────────────────────────\n\n・投稿者： %member_handle% さん\n・クチコミ\n\n%buz_content%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nクチコミを表示設定にすると、%prof_caption%のプロフィールページに\nクチコミを表示して、%member_caption%さんに見てもらうことが\nできるようになります。\n\nクチコミを詳細ページに掲載して多くの%member_caption%さんに\nご覧いただけるようにするためには、以下の操作をお願いいたします。\n\n＜クチコミ表示方法＞\n1．%prof_caption%管理画面にログイン\n　  %ssl_host_url%/WTE/prof.cgi\n\n2．ダッシュボードの右下にあるクチコミ管理をご確認ください。\n　  【操作】欄にて、表示/非表示を切り替えることが可能です。\n　※こちらに表示がない場合は、【クチコミ管理はこちらから】を\n　　クリックして、操作をお願いします。\n\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('dwn9001', 'Subject: [%product_name%] <TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>購入通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n下記の通り<TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>商品の購入手続きが完了しました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご購入商品\n──────────────────────────────────\n\n・商品名　：%dwn_title%\n・商品種別：<TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>\n\n・ご利用方法\n以下のアドレスにブラウザーからアクセスしてください。\n%ssl_host_url%/WTE/mypage.cgi?m=dwndtlfrm&dwn_id=%dwn_id%\n\n・有効期限：%dsl_expire_0%/%dsl_expire_1%/%dsl_expire_2% %dsl_expire_3%:%dsl_expire_4%:%dsl_expire_5% まで\n※有効期限を過ぎると、再度ダウンロードが必要となります。\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('dwn9002', 'Subject: [%product_name%] <TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>購入通知\nSender: %member_handle% 様\nFrom: %member_email%\nTo: %pub_from%\n\nご担当者様\n\n下記の通り<TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>商品が購入されました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご購入商品\n──────────────────────────────────\n\n・購入会員：[%member_id%] %member_handle% 様\n・商品名　：[%dwn_id%] %dwn_title%\n・商品種別：<TMPL_IF NAME=\"dwn_type_1\">動画</TMPL_IF><TMPL_IF NAME=\"dwn_type_2\">PDF</TMPL_IF>\n・有効期限：%dsl_expire_0%/%dsl_expire_1%/%dsl_expire_2% %dsl_expire_3%:%dsl_expire_4%:%dsl_expire_5% まで\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nその他、システム管理画面のDL商品管理にて一覧をご確認いただけます。\n\nどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('lsn9001', 'Subject: 【ワールドトーク】%lsn_stime_n%月%lsn_stime_j%日%stime%から%course_name%があります\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: worldtalk@writeup.co.jp\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n本日は%course_name%があります。\nお時間になりましたら、レッスンURLへご入室ください。\n\n───────────────────────────\n\n▼講座名\n　%course_name%\n\n▼レッスン日時\n　%lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n▼レッスンURL\n　%course_meeting_url%\n<TMPL_IF NAME=\"course_meeting_id\">　ミーティング ID：%course_meeting_id%\n　パスコード：%course_meeting_pass%\n　※レッスンは毎回同じURLで行われます。ID・パスコードも同じです。</TMPL_IF>\n\n▼講師\n　%prof_handle% 先生\n\n▼シラバス\n　%course_syllabus%\n\n▼教材GoogleDrive(アーカイブ・宿題など）\n　%course_material_drive_url%\n\n───────────────────────────\n\n%course_mail_s%\n\n───────────────────────────\n\nそれでは、ワールドトークでのグループ講座レッスンをお楽しみ下さい。\n皆さんにとって、本日が皆様の英語学習の一助となることを\n事務局スタッフ一同、心より願っております。\n\n今後とも講師共々、ワールドトークをよろしくお願いします。\n\n%pub_common_mail_footer%'),
('lsn9002', 'Subject: 【ワールドトーク】%lsn_stime_n%月%lsn_stime_j%日%stime%から%course_name%があります\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\nBcc: worldtalk@writeup.co.jp\n\n%prof_handle% 先生\n\nこんにちは、%product_name%運営事務局です。\n\n本日は%course_name%があります。\nレッスンの準備をお願いいたします。\n\n▼講座名\n　%course_name%\n\n▼レッスン日時\n　%lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n▼レッスンURL\n　%course_meeting_url%\n<TMPL_IF NAME=\"course_meeting_id\">　ミーティング ID：%course_meeting_id%\n　パスコード：%course_meeting_pass%\n　※レッスンは毎回同じURLで行われます。ID・パスコードも同じです。</TMPL_IF>\n\n▼会員\n　%member_handle% さん\n\n▼シラバス\n　%course_syllabus%\n\n▼教材GoogleDrive(アーカイブ・宿題など）\n　%course_material_drive_url%\n\n───────────────────────────\n\n本レッスンはグループ講座レッスンです\n\n■レッスンの流れ\n-----------------------------\n1.授業開始前にZoomURLをクリックします\n2.時間になったらルームに入室ができます\n3.参加者が揃い次第レッスンスタートしてください\n\n【お願いしたいこと】\n\n・Zoom URLを起動した状態でお待ちください\n\n・Zoomに入室できない場合は、運営事務局までご連絡ください\n　customer@worldtalk.jp\n\n───────────────────────────\n\nそれでは、ワールドトークでのグループ講座レッスンをお願いします。\n今後ともよろしくお願いします。\n\n%pub_common_mail_footer%'),
('lsn9011', 'Subject: 【ワールドトーク】%course_name%お疲れ様でした\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: worldtalk@writeup.co.jp\n\n%member_handle% 様\n\nこんにちは、ワールドトークです。\n%course_name%お疲れさまでした。\n\n───────────────────────────\n\n下記の通り、レッスンが終了しました。\n\n▼講座名\n　%course_name%\n\n▼レッスン日時\n　%lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n▼レッスンURL\n　%course_meeting_url%\n<TMPL_IF NAME=\"course_meeting_id\">　ミーティング ID：%course_meeting_id%\n　パスコード：%course_meeting_pass%\n　※レッスンは毎回同じURLで行われます。ID・パスコードも同じです。</TMPL_IF>\n\n▼講師\n　%prof_handle% 先生\n\n▼シラバス\n　%course_syllabus%\n\n▼教材GoogleDrive(アーカイブ・宿題など）\n　%course_material_drive_url%\n\n───────────────────────────\n\n%course_mail_e%\n\n───────────────────────────\n\n引き続き、ワールドトークでのグループ講座レッスンをお楽しみ下さい。\n皆さんにとって、本日が皆様の英語学習の一助となることを\n事務局スタッフ一同、心より願っております。\n\n今後とも講師共々、ワールドトークをよろしくお願いします。\n\n\n%pub_common_mail_footer%'),
('lsn9012', 'Subject:【ワールドトーク】%course_name%お疲れ様でした \nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\nBcc: worldtalk@writeup.co.jp\n\n%prof_handle% 様\n\nこんにちは、ワールドトークです。\n%course_name%お疲れさまでした。\n\n───────────────────────────\n\n下記の通り、レッスンが終了しました。\n\n▼講座名\n　%course_name%\n\n▼レッスン日時\n　%lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n▼レッスンURL\n　%course_meeting_url%\n<TMPL_IF NAME=\"course_meeting_id\">　ミーティング ID：%course_meeting_id%\n　パスコード：%course_meeting_pass%\n　※レッスンは毎回同じURLで行われます。ID・パスコードも同じです。</TMPL_IF>\n\n▼講師\n　%prof_handle% 先生\n\n▼シラバス\n　%course_syllabus%\n\n▼教材GoogleDrive(アーカイブ・宿題など）\n　%course_material_drive_url%\n\n───────────────────────────\n\n本レッスンはグループ講座レッスンです\n\nトラブル、または不明点があれば以下にご連絡ください\n　customer@worldtalk.jp\n\n今後ともよろしくお願いします。\n\n%pub_common_mail_footer%'),
('mpg9001', 'Subject: [%product_name%] 退会通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\n退会を承りました。\n\n会員登録はいつでも可能です。機会がございましたらぜひまたご利用ください。\n\n%pub_common_mail_footer%'),
('mpg9011', 'Subject: [%product_name%] お問い合わせ\nSender: %member_handle% 様\nFrom: %member_email%\nTo: %pub_from%\n\nご担当者様\n\n会員よりお問い合わせがありました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■会員情報\n──────────────────────────────────\n\n会員ID：%member_id%\n姓名：%member_lastname% %member_firstname%\nニックネーム：%member_handle%\nメールアドレス：%member_email%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ日時\n──────────────────────────────────\n\n%tm_0%/%tm_1%/%tm_2% %tm_3%:%tm_4%:%tm_5%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ内容\n──────────────────────────────────\n%inq_title_caption%\n──────────────────────────────────\n%inq_cont%\n\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせが増えてきたと思ったら・・・\n──────────────────────────────────\n\n▼よくある問い合わせページに質問を追加しましょう\n　 よくある問い合わせ：%ssl_host_url%/wte/faq/ \n　 問い合わせに返信する際に、「こちらのページに詳しい記載を行っています」と\n　 ご案内をすることが出来るので、問い合わせ対応時間が減ります。\n\n▼メールテンプレートを作成しましょう\n　 毎回ひとつひとつメールを書いていると、時間があっという間に過ぎてしまいます。\n　 同じような問い合わせがたくさん来るようであれば、テンプレートを作りましょう。\n　 テンプレートの内容は、問い合わせ対応を繰り返しながら推敲していくと\n　 より一層伝わりやすい内容になっていきます。\n\n▼署名に記載してみましょう\n　 問い合わせ対応をするときの署名に、良くある問い合わせTOP3を\n　 記載してみてはいかがでしょうか？\n　 あらかじめこんな問い合わせをいただきます！と記載しておくことで\n　 %member_caption%様が問い合わせをする前に目を通してもらうことが\n　 できます。ぜひ、お試しください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('mpg9012', 'Subject: [%product_name%] お問い合わせを承りました。\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\nご利用ありがとうございます、%product_name%運営事務局です。\n問い合わせありがとうございました。内容を確認し担当者より追ってご連絡します。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ日時\n──────────────────────────────────\n\n%tm_0%/%tm_1%/%tm_2% %tm_3%:%tm_4%:%tm_5%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ内容\n──────────────────────────────────\n%inq_title_caption%\n──────────────────────────────────\n%inq_cont%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nまた、こちらのページによくあるお問い合わせをまとめております。\nご参考いただけますと幸いです。\nよくあるご質問：%ssl_host_url%/wte/faq/\n\n今後とも、%product_name%をどうぞ宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('mpg9013', 'Subject: [%product_name%] お問い合わせ\nSender: %inq_name% 様\nFrom: %inq_email%\nTo: %pub_from%\n\nご担当者様\n\n会員よりお問い合わせがありました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ日時\n──────────────────────────────────\n\n%tm_0%/%tm_1%/%tm_2% %tm_3%:%tm_4%:%tm_5%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お客様情報\n──────────────────────────────────\n\n・お名前：%inq_name%\n・メールアドレス：%inq_email%\n・登録状況：%inq_mtype_caption%\n・お問い合わせ項目：%inq_title_caption%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ内容\n──────────────────────────────────\n\n%inq_cont%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('mpg9014', 'Subject: [%product_name%] お問い合わせを承りました。\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %inq_email%\n\n%inq_name% 様\n\nご利用ありがとうございます、%product_name%運営事務局です。\n問い合わせありがとうございました。内容を確認し担当者より追ってご連絡します。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ日時\n──────────────────────────────────\n\n%tm_0%/%tm_1%/%tm_2% %tm_3%:%tm_4%:%tm_5%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お客様情報\n──────────────────────────────────\n\n・お名前：%inq_name%\n・メールアドレス：%inq_email%\n・登録状況：%inq_mtype_caption%\n・お問い合わせ項目：%inq_title_caption%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■お問い合わせ内容\n──────────────────────────────────\n\n%inq_cont%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nまた、こちらのページによくあるお問い合わせをまとめております。\nご参考いただけますと幸いです。\nよくあるご質問：%ssl_host_url%/wte/faq/\n\n今後とも、%product_name%をどうぞ宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('msg9001', 'Subject: [%product_name%] メッセージ送信通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り%prof_handle%さんにメッセージを送信いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■送信内容\n──────────────────────────────────\n\n・レッスン： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・宛先： %prof_handle% さん\n・メッセージ\n\n%msg_content%\n\n・レッスン確認ページはこちら\n%ssl_host_url%/WTE/mypage.cgi?m=lsndtlfrm&lsn_id=%lsn_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nメッセージはいつでも送信することが可能です。\nその他にもお伝えしたいことがございましたら、ご利用ください。\n\n＜おすすめメッセージ内容＞\n・実施したいレッスンの内容について\n　(単語の練習がしたい、●●●なシチュエーションで会話をしたい、等)\n\n・前回のレッスン内容について\n　(先日は、テキストの●ページまでやったので、今日は●ページから・・等)\n\n\nお時間によっては、%prof_caption%がメッセージを確認できない場合も\nございますので、ご了承くださいませ。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('msg9002', 'Subject: [%product_name%] メッセージ受信通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%prof_lastname% %prof_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り%member_handle%さんからメッセージを受信いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■受信内容\n──────────────────────────────────\n\n・レッスン： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・差出人： %member_handle% さん\n・メッセージ\n\n%msg_content%\n\n・レッスン確認ページはこちら\n%ssl_host_url%/WTE/prof.cgi?m=lsndtlfrm&lsn_id=%lsn_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nもし、返答する必要がある場合は、以下の方法にて実施することができます。\n\n＜メッセージ送信方法＞\n1. %prof_caption%管理画面にログインします\n　 %ssl_host_url%/WTE/prof.cgi\n\n2. メッセージを受信されたレッスン日時をクリックします\n　 日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n3. メッセージ送信フォームに、メッセージを記入して【送信する】をクリックすれば完了です！\n\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('msg9011', 'Subject: [%product_name%] メッセージ受信通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n\n%prof_handle%さんからメッセージを受信いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■受信内容\n──────────────────────────────────\n\n・レッスン： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・差出人： %prof_handle% さん\n・メッセージ\n\n%msg_content%\n\n・レッスン確認ページはこちら\n%ssl_host_url%/WTE/mypage.cgi?m=lsndtlfrm&lsn_id=%lsn_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nこちらのメッセージに返信される場合は、以下の方法で実施が可能です。\n\n＜メッセージ送信方法＞\n1. %member_caption%マイページにログインします\n　 %ssl_host_url%/WTE/mypage.cgi\n\n2. サイドメニューの中から【予約確認】をクリックします\n\n3. メッセージを受信されたレッスン日時をクリックします\n　 日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n4. メッセージ送信フォームに、メッセージを記入して【送信する】をクリックすれば完了です！\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('msg9012', 'Subject: [%product_name%] メッセージ送信通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_lastname% %prof_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り%member_handle%さんへメッセージを送信いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■受信内容\n──────────────────────────────────\n\n・レッスン： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・送信先： %member_handle% さん\n・メッセージ\n\n%msg_content%\n\n・レッスン確認ページはこちら\n%ssl_host_url%/WTE/prof.cgi?m=lsndtlfrm&lsn_id=%lsn_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('pay9001', 'Subject: [%product_name%] 銀行振込申請を承りました\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n以下の通り、銀行振込申請を承りました。\nポイントご利用までの流れを下記に記載しておりますので、\nご一読をお願いいたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■申請内容\n──────────────────────────────────\n会員ID：%member_id%\n登録アドレス：%member_email%\nプラン： %pln_title%（%pln_point_with_comma% pt／%pln_price_with_comma% 円）\nお振込名（カナ）： %kana%\nお振込予定日： %date%\n備考：\n%note%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ポイントご利用までの流れ\n──────────────────────────────────\n1. 下記の口座へ、ご記入いただいた振込予定日までにお振込をお願いします。\n\n　　=====================================\n　　AAA銀行／ABC支店　普通預金　1234567\n　　口座名義　カブシキカイシャライトアップ\n　　=======================================\n\n2. お振込の際は、お振込名義の前に【会員ID】を必ず入力してください。\n　例）会員ID　1234　ヤマダハナコ様の場合「1234ヤマダハナコ」\n　\n　会員IDの記載がない場合、会員様の特定が出来ず、ポイントの付与が\n　出来かねる場合がございますので、ご協力お願いいたします。\n　※会員IDは、上記に記載しております【申請内容】内に記述しております\n\n3. 弊社にて入金確認を行います。確認には振込日を含めて2～3営業日いただきます。\n　（営業日に土日祝日は含まれません。ご注意ください。）\n\n4. 入金の確認が完了次第、ポイントの付与を行います。\n\n5. ポイントの付与が完了しましたら、%product_name%運営事務局より\n　ご連絡をさせていただきます。ご連絡当日より、ポイントをご利用いただけます。\n\n【注意事項】\n・お振込日を含め、5日以上経過しても%product_name%運営事務局より\n　連絡が無い場合は、お手数ですがお問い合わせフォームよりご連絡くださいませ。\n　※年末年始、お盆休み、ゴールデンウィークは5日以上お日にちをいただく\n　　場合がございます。\n\n・会員IDの入力を忘れてお振込された場合は、%product_name%運営事務局まで\n　ご連絡をお願いいたします。\n\n今後とも、%product_name%をどうぞ宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('pay9002', 'Subject: [%product_name%] 銀行振込申請\nSender: %member_lastname% %member_firstname% 様\nFrom: %member_email%\nTo: %pub_from%\n\nご担当者様\n\n%member_caption%より銀行振込申請がありました。\n以下の情報をご確認ください。\n\n銀行振込の場合、ポイントは手動での付与となりますので\n入金の確認後、ポイントの付与をお願いいたします。\n※今後の流れについても以下に記載しております。\n　対応方法にご不明な点がある方はご参考ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■会員情報\n──────────────────────────────────\n\n姓名：%member_lastname% %member_firstname%\nE-mail：%member_email%\n%member_caption%ID：%member_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■申請内容\n──────────────────────────────────\n\nプラン： %pln_title%（%pln_point_with_comma% pt／%pln_price_with_comma% 円）\nお振込名（カナ）： %kana%\nお振込予定日： %date%\n備考：\n%note%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■今後の流れ\n──────────────────────────────────\n1. 上記に記載のあるお振込予定日（%date%）に、入金を確認します\n\n2. 入金確認が取れましたら、システム管理画面にログインしてください\n　 %ssl_host_url%/WTE/admin.cgi\n\n3. %member_caption%管理をクリックし、%member_caption%のIDで該当者の検索をします。\n　 ※%member_caption%の方には、振込名義の前に%member_caption%IDを入力してもらっています。\n   ※IDの記載がない場合は、メールアドレスで検索を行いましょう\n\n4. Pチャージをクリックし、チャージポイントの概要を\n 【加算(銀行振込単発ポイント購入】のままで、振り込んでいただいた金額に\n   応じてポイントの付与をします\n\n5. %member_caption%に連絡をして、完了です！\n\nご不明な点がございましたら、運営事務局までご連絡ください\n\n今後とも%product_name%をどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('pdm9001', 'Subject: [%product_name%] 請求申請通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り請求申請を受領いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %pdm_id%\n・請求金額： %pdm_price_with_comma% pt\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nお支払いが完了いたしましたら、運営事務局よりご連絡いたしますので\nもうしばらくお待ちくださいませ。\n\nまた、請求の状態は、%prof_caption%管理画面の【請求集計】ページでも\nご確認いただくことが可能です。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('pdm9002', 'Subject: [%product_name%] %prof_caption%請求申請通知\nSender: %prof_lastname% %prof_firstname% 様\nFrom: %prof_email%\nTo: %pub_from%\n\nご担当者様\n\n下記の通り、%prof_caption%より請求申請を受領いたしました。\n請求内容をご確認のうえ、お支払いをお願いいたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■申請内容\n──────────────────────────────────\n\n・請求%prof_caption%： [%prof_id%] %prof_handle%\n・請求ＩＤ： %pdm_id%\n・請求金額： %pdm_price_with_comma% pt\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■今後の流れ\n──────────────────────────────────\nお支払いが完了いたしましたら、支払完了の処理をお願いします。\n\n＜支払完了処理＞\n1. システム管理画面にログインします\n    %ssl_host_url%/WTE/admin.cgi\n\n2. メニュー　%prof_caption%精算　をクリックします\n\n3. 支払が完了した%prof_caption%を選び、ステータス列にある\n  【支払済みにする】をクリックします\n\n4. こちらが完了すると、精算通知が管理者・%prof_caption%に送られます。\n\nどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('pdm9011', 'Subject: [%product_name%] 精算通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n下記の通り精算を完了しましたので、ご報告いたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %pdm_id%\n・精算金額： %pdm_price_with_comma% pt\n・精算日時： %tm_0%/%tm_1%/%tm_2%\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nご不明な点がございましたら、お気軽にお問い合わせください。\n※なお、お振込のご確認が確実に出来るのは翌日となります。\n\nこれまでの請求履歴などは、%prof_caption%管理画面【請求集計】にて\nご確認いただくことが可能です。\n気になる方は、こちらをご参考ください。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('pdm9012', 'Subject: [%product_name%] %prof_caption%精算通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %pub_from%\n\nご担当者様\n\n下記の通り精算を完了しました。\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %pdm_id%\n・請求者　： [%prof_id%] %prof_lastname% %prof_firstname% 様\n・精算金額： %pdm_price_with_comma% pt\n・精算日時： %tm_0%/%tm_1%/%tm_2%\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nこちらの通知は、該当する%prof_caption%にも送られております。\n\nどうぞ、宜しくお願いいたします。'),
('pex9001', 'Subject: [%product_name%] ポイント有効期限のお知らせ\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\nご利用のポイントの失効日が近づいています。\n失効日になるまえにぜひご利用ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■現在のポイント\n──────────────────────────────────\n▼保持ポイント\n　%member_point_with_comma% pt\n\n▼有効期限\n　%member_point_expire_Y%年%member_point_expire_n%月%member_point_expire_j%日（%member_point_expire_wj%）\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nその他よくあるご質問については、以下のページをご参考くださいませ。\n　◆よくあるご質問：%ssl_host_url%/wte/faq/\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('ppl9001', 'Subject: [%product_name%] カード決済通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: %pub_from%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n以下の通り、カード決済を承りました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■決済内容\n──────────────────────────────────\n決済日時　　：%crd_rdate_Y%年%crd_rdate_n%月%crd_rdate_j%日(%crd_rdate_wj%) %crd_rdate_H%:%crd_rdate_i%:%crd_rdate_s%\n決済処理結果：<TMPL_IF NAME=\"crd_success_1\">成功</TMPL_IF><TMPL_IF NAME=\"crd_success_2\">失敗</TMPL_IF><TMPL_IF NAME=\"crd_success_3\">保留</TMPL_IF>\n請求書ＩＤ　：%crd_id%\n受領書ＩＤ　：%crd_receipt_id%\nご購入プラン：[%pln_id%] %pln_title%\nお支払い金額：%crd_price_with_comma% 円\n追加ポイント：%crd_point_with_comma% pt\n<TMPL_IF NAME=\"pln_subscription\">\n※こちらのプランは月額定額制プランのため、来月からは自動的に毎月 %pln_price_with_comma% 円 が課金され、%pln_point_with_comma% pt が追加されます。\n</TMPL_IF>\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n現在所持されているポイントは、マイページにログイン後ご確認いただけます。\n\nそれでは、今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('ppl9003', 'Subject: [%product_name%] カード決済保留通知\nSender: %prof_handle% 様\nFrom: %member_email%\nTo: %pub_from%\n\nご担当者様\n\nカード決済が保留になりました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■決済内容\n──────────────────────────────────\n\n会員情報　　：[%member_id%] %member_lastname% %member_firstname% 様\n決済日時　　：%crd_rdate_Y%年%crd_rdate_n%月%crd_rdate_j%日(%crd_rdate_wj%) %crd_rdate_H%:%crd_rdate_i%:%crd_rdate_s%\n決済処理結果：保留\n請求書ＩＤ　：%crd_id%\n受領書ＩＤ　：%crd_receipt_id%\nご購入プラン：[%pln_id%] %pln_title%\nお支払い金額：%crd_price_with_comma% 円\n追加ポイント：%crd_point_with_comma% pt\nIPNメッセージ：%crd_ipn_message%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('ppl9011', 'Subject: [%product_name%] カード月次課金完了通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\n今月分のカード月次課金が完了しましたので、ご案内申し上げます。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■決済内容\n──────────────────────────────────\n\n決済日時　　：%crd_rdate_Y%年%crd_rdate_n%月%crd_rdate_j%日(%crd_rdate_wj%) %crd_rdate_H%:%crd_rdate_i%:%crd_rdate_s%\n請求書ＩＤ　：%crd_id%\nご購入プラン：%pln_id%\nお支払い金額：%crd_price_with_comma% 円\n追加ポイント：%crd_point_with_comma% pt\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('ppl9012', 'Subject: [%product_name%] カード月次課金失敗通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: %pub_from%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n加入いただいているコースの今月分のカード決済次が失敗しました。\n\n失敗の原因については、運営事務局では分かりかねる場合がございます。\nお手数ではございますが、一度クレジットカード会社にご連絡いただけますでしょうか。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■決済内容\n──────────────────────────────────\n\n決済日時　　：%crd_rdate_Y%年%crd_rdate_n%月%crd_rdate_j%日(%crd_rdate_wj%) %crd_rdate_H%:%crd_rdate_i%:%crd_rdate_s%\n決済処理結果：失敗\n請求書ＩＤ　：%crd_id%\nご購入プラン：%pln_id%\nお支払い金額：%crd_price_with_comma% 円\n追加ポイント：%crd_point_with_comma% pt\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nなお、決済の失敗によりご加入いただいているコースは解約いたしました。\n再度コースの加入をご希望の場合は、お手数ではございますが\n再度お申し込みをお願いいたします。\n\n＜コースお申込み方法＞\n1. マイページにログインします\n　 %ssl_host_url%/WTE/mypage.cgi\n\n2. サイドメニューのカード決済をクリックします\n\n3. ご希望のコースを選び、説明に従ってお申し込みください\n\nその他ご不明な点がございましたら、運営事務局へご連絡ください。\n\n今後とも、%product_name%を宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('ppl9021', 'Subject: [%product_name%] カード月次課金解約通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: %pub_from%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n以下の月額課金コースの解約を承りました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■解約内容\n──────────────────────────────────\n\n解約日時　　：%auto_sdate_Y%年%auto_sdate_n%月%auto_sdate_j%日(%auto_sdate_wj%)  %auto_sdate_H%:%auto_sdate_i%:%auto_sdate_s%\nご解約プラン：%pln_id%\n月額金額　　：%auto_price_with_comma% 円\n月次ポイント：%auto_point_with_comma% pt\n決済日　　　：毎月%auto_day%日\n最終課金日　：%auto_mdate_Y%年%auto_mdate_n%月%auto_mdate_j%日(%auto_mdate_wj%) \n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n%product_name%のご利用、ありがとうございました。\n\nご不明な点がございましたら、お気軽に運営事務局にお問い合わせください。\nどうぞ、宜しくお願いいたします。\n%pub_common_mail_footer%'),
('prg9001', 'Subject: [%product_name%] %prof_caption%仮登録通知\nSender: %prof_handle% 様\nFrom:  %prof_email%\nTo: %pub_from%\n\n\n%product_name%の%prof_caption%登録のお手続きがありました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご登録内容\n──────────────────────────────────\n\n・%prof_lastname_caption%/%prof_firstname_caption%：%prof_lastname% %prof_firstname%\n・%prof_handle_caption%：%prof_handle%\n・%prof_email_caption%：%prof_email%\n・%prof_pass_caption%：ご入力いただいたパスワード\n・%prof_hp_caption%：%prof_hp%\n・住所：〒%prof_zip1%-%prof_zip2%　%prof_addr1% %prof_addr2% %prof_addr3% %prof_addr4%\n・電話番号：%prof_tel1%-%prof_tel2%-%prof_tel3%\n・%prof_gender_caption%：<TMPL_IF NAME=\"prof_gender_1\">男性</TMPL_IF><TMPL_IF NAME=\"prof_gender_2\">女性</TMPL_IF>\n・%prof_country_caption%：%prof_country_name%\n・%prof_residence_caption%：%prof_residence_name%\n・%prof_character_caption%：<TMPL_LOOP NAME=\"prof_character_loop\">%title%　</TMPL_LOOP>\n・%prof_interest_caption%：<TMPL_LOOP NAME=\"prof_interest_loop\">%title%　</TMPL_LOOP>\n\n・%prof_intro_caption%：\n%prof_intro%\n\n・%prof_app1_caption%：\n%prof_app1%\n\n・%prof_app2_caption%：\n%prof_app2%\n\n・%prof_app3_caption%：\n%prof_app3%\n\n・%prof_app4_caption%：\n%prof_app4%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('prg9002', 'Subject: [%product_name%] %prof_caption%仮登録通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n\n%prof_handle% 様\n\nこんにちは、%product_name%運営事務局です。\nこの度は%product_name%の%prof_caption%登録のお手続きを頂き、ありがとうございました。\n仮登録が完了いたしましたので、ご案内いたします。\n審査が終わり次第、ご連絡いたしますので、しばらくお待ちください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご登録内容\n──────────────────────────────────\n\n・%prof_lastname_caption%/%prof_firstname_caption%：%prof_lastname% %prof_firstname%\n・%prof_handle_caption%：%prof_handle%\n・%prof_email_caption%：%prof_email%\n・%prof_pass_caption%：ご入力いただいたパスワード\n・%prof_hp_caption%：%prof_hp%\n・住所：〒%prof_zip1%-%prof_zip2%　%prof_addr1% %prof_addr2% %prof_addr3% %prof_addr4%\n・電話番号：%prof_tel1%-%prof_tel2%-%prof_tel3%\n・%prof_gender_caption%：<TMPL_IF NAME=\"prof_gender_1\">男性</TMPL_IF><TMPL_IF NAME=\"prof_gender_2\">女性</TMPL_IF>\n・%prof_country_caption%：%prof_country_name%\n・%prof_residence_caption%：%prof_residence_name%\n・%prof_character_caption%：<TMPL_LOOP NAME=\"prof_character_loop\">%title%　</TMPL_LOOP>\n・%prof_interest_caption%：<TMPL_LOOP NAME=\"prof_interest_loop\">%title%　</TMPL_LOOP>\n\n・%prof_intro_caption%：\n%prof_intro%\n\n・%prof_app1_caption%：\n%prof_app1%\n\n・%prof_app2_caption%：\n%prof_app2%\n\n・%prof_app3_caption%：\n%prof_app3%\n\n・%prof_app4_caption%：\n%prof_app4%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n今後とも当サービスをよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('pwd9001', 'Subject: [%product_name%] パスワード初期化\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nさきほどご利用になったブラウザーのアドレス欄に以下のURLを入れて、\nパスワード初期化ページにアクセスしてください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■パスワードの初期化\n──────────────────────────────────\n\n%ssl_host_url%/WTE/pwdrst.cgi?m=pwdintfrm&token=%token%\n\n※有効期限：%pwdrst_expire_0%-%pwdrst_expire_1%-%pwdrst_expire_2% %pwdrst_expire_3%:%pwdrst_expire_4%:%pwdrst_expire_5%まで\n※有効期限が過ぎると設定できなくなりますのでご注意ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%pub_common_mail_footer%'),
('pwd9002', 'Subject: [%product_name%] パスワード初期化\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nパスワードの初期化が完了しました。\n\n%pub_common_mail_footer%\n'),
('reg9001', 'Subject: [%product_name%] 会員仮登録通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\nこの度は%product_name%の会員登録のお手続きを頂き、ありがとうございました。\n仮登録が完了いたしましたので、ご案内いたします。\n以下のページにブラウザーでアクセスして本登録を完了してください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■本登録のお手続きURL\n──────────────────────────────────\n\n%ssl_host_url%/WTE/honreg.cgi?i=%member_id%&p=%member_passphrase%&s=%seller_id%&loginid=1\n\n※有効期限： %reg_interim_expire_0%-%reg_interim_expire_1%-%reg_interim_expire_2% まで\n※有効期限が過ぎると再度仮登録が必要となりますのでご注意ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n本登録が完了するまでサービスをご利用頂けませんのでご注意ください。\n※本登録が完了いたしましたら、プロフィールの編集をお願いいたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご登録内容\n──────────────────────────────────\n\n・お名前：%member_lastname% %member_firstname%\n・ニックネーム：%member_handle%\n・メールアドレス：%member_email%\n・クーポン：<TMPL_IF NAME=\"coupon_price\">%coupon_price_with_comma% ポイント分</TMPL_IF>\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n今後とも当サービスをよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('reg9002', 'Subject: [%product_name%] 会員本登録通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\nBcc: %pub_from%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\nこの度は%product_name%の会員登録のお手続きを頂き、ありがとうございました。\n本登録が完了いたしましたので、ご案内いたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご登録内容\n──────────────────────────────────\n\n・お名前：%member_lastname% %member_firstname%\n・ニックネーム：%member_handle%\n・メールアドレス：%member_email%\n・パスワード：設定いただいたパスワードです\n・クーポン：<TMPL_IF NAME=\"coupon_price\">%coupon_price_with_comma% ポイント分</TMPL_IF>\n\n%product_name%にログイン：%ssl_host_url%/WTE/mypage.cgi\nよくあるご質問：%ssl_host_url%/wte/faq/\n＊ブックマークをしておくと便利です\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nまた、簡単に%product_name%のご説明をさせていただきます。\nご一読いただけますと幸いです。\n\n　Ｑ．どんな%prof_caption%とレッスンできますか？\n　─────────────────────────────────\n　こちらが%prof_caption%の一覧となります。\n　%ssl_host_url%/wte/prflstfrm/ \n　\n　%ssl_host_url%/wte/prflstfrm/ のページで【詳細検索を開く】を\n　クリックすると、あなたにあった%prof_caption%の検索がより簡単に\n　なりますので、ぜひお試しください。\n\n\n　Ｑ．月額定額制のコースに申し込むには、どうするのですか？\n　─────────────────────────────────\n　「マイページ」→「カード決済」をクリックすると、申込みページになります。\n　Paypalを使った、クレジットカード決済となります。\n　皆さんのカード番号は、%product_name%運営事務局では知らされず、\n　世界最大規模の決済会社「Paypal」が厳重に管理いたしますのでご安心ください。\n　\n　◆料金について：%ssl_host_url%/wte/plan/  ※画面最下部参照\n　◆PayPalとは：https://www.paypal.com/jp/\n　\n\n　Ｑ．必要なものは何ですか？\n　─────────────────────────────────\n　「Google Meet」と「マイク」と「WEBカメラ」の３点です。\n　無料体験にて、接続環境なども合わせてお試しください。\n\n　教室に通うよりもより手軽に、レッスンを行うことができます！\n\n　>>参加までの流れ：%ssl_host_url%/wte/lesson/\n　>>必要機材：%ssl_host_url%/wte/starter/\n\n\n　その他にも気になることがあれば、ぜひ以下のページをご参考ください。\n　%product_name%とは：%ssl_host_url%/wte/about/\n　よくある質問：%ssl_host_url%/wte/faq/\n\n　まずは無料体験で、%product_name%を体験していただき、\n　気に入っていただけましたら、お得な月額会員コースをご利用くださいませ。\n\n　今後とも%prof_caption%や運営事務局スタッフ一同を\n　どうぞ、宜しくお願いいたします。\n\n　　　▼早速ログインされる方はこちらから▼\n　　　　%ssl_host_url%/WTE/mypage.cgi\n\n%pub_common_mail_footer%'),
('rep9001', 'Subject: [%product_name%] レッスン報告の確認\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %pub_from%\n\nご担当者様\n\nレッスン報告をご確認ください。\nステータスに変更がある場合は、早急に管理画面上にて変更をお願いします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■レッスン報告内容\n──────────────────────────────────\n・レッスンID： %lsn_id%\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n\n・%prof_caption%： [%prof_id%] %prof_handle%\n　　報告内容　：<TMPL_IF NAME=\"lsn_prof_repo_1\">完了</TMPL_IF><TMPL_IF NAME=\"lsn_prof_repo_2\">未実施（相手が来ない）</TMPL_IF><TMPL_IF NAME=\"lsn_prof_repo_3\">トラブル（自分）</TMPL_IF><TMPL_IF NAME=\"lsn_prof_repo_9\">その他</TMPL_IF>\n　　メッセージ：%lsn_prof_repo_note%\n\n・%member_caption%： [%member_id%] %member_handle%\n　　報告内容　：<TMPL_IF NAME=\"lsn_member_repo_1\">完了</TMPL_IF><TMPL_IF NAME=\"lsn_member_repo_2\">未実施（相手が来ない）</TMPL_IF><TMPL_IF NAME=\"lsn_member_repo_3\">トラブル（自分）</TMPL_IF><TMPL_IF NAME=\"lsn_member_repo_9\">その他</TMPL_IF>\n　　メッセージ：%lsn_member_repo_note%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■今後の流れ\n──────────────────────────────────\n1. まずは報告内容をご確認ください。お互いの報告に相違がある場合は\n　 運営事務局の判断にお任せいたします。\n\n2. ステータスを変更する場合は、システム管理画面にログインします\n　 %ssl_host_url%/WTE/admin.cgi\n\n3. メニューのレッスン管理をクリックします\n\n4. 該当のレッスンの詳細ページを開きます\n\n5. 売上確定報告期間が過ぎていなければ、こちらのページで\n　 ステータスを変更することが出来ます\n　 %member_caption%の課金対象となるか否か、設定をお願いします\n\nどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('rsv9001', 'Subject: [%product_name%] レッスン予約通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n下記の通りレッスンを予約いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n▼授業名\n　 %course_name%\n\n▼日時\n　 %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n　※上記に記載されている終了時間の5分前にはレッスンが完了いたします。\n　　最後の5分については、%prof_caption%が次のレッスンに移動するための時間になりますので\n　　あらかじめ、ご了承くださいませ。\n\n▼%prof_caption%情報\n　担当%prof_caption%： %prof_handle% 先生\n　%prof_caption% %prof_hp_caption%： %prof_hp%\n\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■レッスンが始まる前に・・・\n──────────────────────────────────\n・%prof_caption%にどんなレッスンをしたいのか、伝えておきましょう！\n\n　レッスン時間は限られています、より充実したレッスンを実施するためにも\n　「どんなことを学びたいのか」「何を克服したいのか」などを\n　%prof_caption%にメッセージで伝えておきましょう。\n\n　＜メッセージ送信方法＞\n　1. サイトにログイン後、サイドメニュー【レッスン確認・報告】をクリック。\n　2. メッセージを送りたい【レッスン日時】をクリック。\n　3. メッセージ枠に記入をして【送信する】ボタンをクリック。\n\n\n・Google Meetの設定を確認！\n\n　レッスン開始の10分前までに、Google Meetを立ち上げて、\n　スピーカー、マイク、Webカメラの接続テストを行いましょう。\n\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■もしもキャンセルするときは・・・\n──────────────────────────────────\n　キャンセルをするには、マイページにログインをし、\n　メニューの【予約確認】をクリック。\n　キャンセルをするレッスンを選び、キャンセルフォームに\n　理由を記入して、キャンセルの処理を行ってください。\n\n　※一定のお時間を過ぎますと緊急キャンセル対象となり、\n　　ポイントが消費いたしますのでご注意ください。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('rsv9002', 'Subject: [%product_name%] レッスン予約通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_handle% 様\n\n下記の通りレッスンを予約を承りました。\n%prof_caption%管理画面にログインのうえ、詳細をご確認ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・%member_caption%： %member_handle% さん\n・Zoom URL： %prof_hp%\n\n▼レッスン詳細\n　%ssl_host_url%/WTE/prof.cgi?m=lsndtlfrm&lsn_id=%lsn_id%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■レッスン前に・・・\n──────────────────────────────────\n\n・初めての%member_caption%からの予約なら、メッセージを送ってみてもいいかもしれません\n　もし余裕があれば、%member_caption%にメッセージを送ってみましょう。\n　メッセージは、レッスン詳細のページから簡単に送信することができます。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n--\n%pub_common_mail_footer%'),
('rsv9011', 'Subject: [%product_name%] レッスンのキャンセルを受け付けました\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n下記のレッスンのキャンセルを受け付けました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・%prof_caption%： %prof_handle% 先生\n・キャンセル理由： %lsn_cancel_reason%\n\n　予約済ポイントとなっていたポイントは、自動で返還が行われます。\n　マイページにログインし、ご確認ください。\n　　※緊急キャンセルの場合は、ページに記載があったように\n　　　一部ポイントは消費されます\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n次のレッスンのご予約をお待ちしております。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('rsv9012', 'Subject: [%product_name%] レッスンのキャンセルを受け付けました\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n下記のレッスンのキャンセルを受け付けました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・%member_caption%： %member_handle% さん\n・キャンセル理由： %lsn_cancel_reason%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n今後ともよろしくお願いいたします。\n\n%pub_common_mail_footer%\n\n'),
('rsv9021', 'Subject: [%product_name%] レッスンのキャンセルを受け付けました\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %member_email%\n\n%member_lastname% %member_firstname% 様\n\nこんにちは、%product_name%運営事務局です。\n下記のレッスンのキャンセルを%prof_caption%より受け付けました。\n\n%prof_caption%側の都合とはいえ、せっかくご予約いただいたのに\nレッスンを提供することが出来ず、申し訳ございません。\n\n%prof_caption%より、以下のメッセージが届いておりますので\nご確認くださいませ。\n\n※なお、今回のキャンセルで消費される予定だったポイントは\n　消費されずに、自動で返還されますのでご安心ください。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・%prof_caption%： %prof_handle% さん\n・キャンセル理由： %lsn_cancel_reason%\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('rsv9022', 'Subject: [%product_name%] レッスンのキャンセルを受け付けました\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %prof_email%\n\n%prof_handle% 様\n\nこんにちは、%product_name%運営事務局です。\n\n%prof_lastname% %prof_firstname% 様による、下記のレッスンのキャンセルを\n受け付けましたのでご連絡いたします。\n\nなお、スケジュールの枠も合わせてキャンセルする場合は、\n【スケジュール】メニューをクリックして、キャンセルしたい日時を選びクリックしてください。\nポップアップが表示されますので、【OK】をクリックすれば完了します。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■ご予約内容\n──────────────────────────────────\n\n・授業名：%course_name%\n・日時： %lsn_stime_Y%年%lsn_stime_n%月%lsn_stime_j%日（%lsn_stime_wj%）%stime%～%etime%\n・%member_caption%： %member_handle% さん\n・キャンセル理由： %lsn_cancel_reason%\n\n※こちらのキャンセル理由について等、\n　%member_caption%様にもお送りされております。\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nもし、仕事などの都合により緊急キャンセルが多くなってしまう場合は、\nあらかじめ自己紹介欄にその旨を記載いただけますと幸いです。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('sdm9001', 'Subject: [%product_name%] 請求申請通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %seller_email%\n\n%seller_company% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り請求申請を受領いたしました。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %sdm_id%\n・請求金額： %sdm_price_with_comma% pt\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n%product_name%では、毎月●日を締日、翌月●日にお支払いをしております。\n\nお支払いが完了いたしましたら、運営事務局よりご連絡いたしますので\nもうしばらくお待ちくださいませ。\n\n今後とも当サービスをよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('sdm9002', 'Subject: [%product_name%] 代理店請求申請通知\nSender: %seller_company% 様\nFrom: %seller_email%\nTo: %pub_from%\n\nご担当者様\n\n下記の通り代理店より請求申請を受領いたしました。\n請求内容をご確認のうえ、お支払いをお願いいたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■請求内容\n──────────────────────────────────\n・請求代理店： [%seller_id%] %seller_company%\n・請求ＩＤ： %sdm_id%\n・請求金額： %sdm_price_with_comma% pt\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n■今後の流れ\n──────────────────────────────────\nお支払いが完了いたしましたら、支払完了の処理をお願いします。\n\n＜支払完了処理＞\n1. システム管理画面にログインします\n　%ssl_host_url%/WTE/admin.cgi\n\n2. メニュー　代理店精算　をクリックします\n\n3. 支払が完了した代理店を選び、ステータス列にある\n　【支払済みにする】をクリックします\n\n4. こちらが完了すると、精算通知が管理者・代理店に送られます。\n\nどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%'),
('sdm9011', 'Subject: [%product_name%] 精算通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %seller_email%\n\n%seller_company% 様\n\nこんにちは、%product_name%運営事務局です。\n下記の通り精算を完了しましたのでご報告いたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %sdm_id%\n・精算金額： %sdm_price_with_comma% pt\n・精算日　： %tm_0%/%tm_1%/%tm_2%\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nご不明な点がございましたら、お気軽にお問い合わせください。\n※なお、お振込のご確認が確実に出来るのは翌日となります。\n\n今後とも%product_name%をよろしくお願いいたします。\n\n%pub_common_mail_footer%'),
('sdm9012', 'Subject: [%product_name%] 代理店精算通知\nSender: %pub_sender%\nFrom: %pub_from%\nTo: %pub_from%\n\nご担当者様\n\n下記の通り精算を完了しましたのでご報告いたします。\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n・請求ＩＤ： %sdm_id%\n・代理店　： [%seller_id%] %seller_company%\n・精算金額： %sdm_price_with_comma% pt\n・精算日　： %tm_0%/%tm_1%/%tm_2%\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nこちらの通知は、該当する代理店にも送られております。\n\nどうぞ、宜しくお願いいたします。\n\n%pub_common_mail_footer%');
